function getMinimumTime(tasks) {
    // The minimum time to finish all tasks, regardless of the order or 
    // circular nature, is simply the sum of all task times.
    let totalTime = 0;

    for (let i = 0; i < tasks.length; i++) {
        totalTime += tasks[i];
    }

    return totalTime;
}

// Time Complexity: O(N) where N is the number of tasks in the array.
// Space Complexity: O(1) since we only use a single variable to store the sum.
