function findFirstDuplicate(arr) {
    for (let i = 0; i < arr.length; i++) {
        // Get the absolute value to use as an index
        let val = Math.abs(arr[i]);

        // If the value at index (val - 1) is already negative,
        // it means we have seen this number before.
        if (arr[val - 1] < 0) {
            return val;
        }

        // Otherwise, mark this number as seen by making the 
        // value at index (val - 1) negative.
        arr[val - 1] = -arr[val - 1];
    }

    return -1;
}

// Time Complexity: O(n) - We iterate through the array only once.
// Space Complexity: O(1) - We modify the array in-place without using any additional data structures.
